type Listener = (...args: unknown[]) => void;

interface ListenerEntry {
  fn: Listener;
  once: boolean;
}

export class EventEmitter {
  private _listeners: Map<string, ListenerEntry[]> = new Map();

  // Register listener, return unsubscribe function
  on(event: string, listener: Listener): () => void {
    if (!this._listeners.has(event)) {
      this._listeners.set(event, []);
    }
    const entry: ListenerEntry = { fn: listener, once: false };
    this._listeners.get(event)!.push(entry);
    return () => this._removeEntry(event, entry);
  }

  // Listener fires only once
  once(event: string, listener: Listener): void {
    if (!this._listeners.has(event)) {
      this._listeners.set(event, []);
    }
    const entry: ListenerEntry = { fn: listener, once: true };
    this._listeners.get(event)!.push(entry);
  }

  // Call all listeners, return true if any existed
  emit(event: string, ...args: unknown[]): boolean {
    const entries = this._listeners.get(event);
    if (!entries || entries.length === 0) {
      return false;
    }

    // Snapshot to guard against mid-emit mutations
    const snapshot = [...entries];

    for (const entry of snapshot) {
      if (entry.once) {
        this._removeEntry(event, entry);
      }
      entry.fn(...args);
    }

    return true;
  }

  // Remove specific listener by function reference
  off(event: string, listener: Listener): void {
    const entries = this._listeners.get(event);
    if (!entries) return;

    const index = entries.findIndex((e) => e.fn === listener);
    if (index !== -1) {
      entries.splice(index, 1);
      if (entries.length === 0) {
        this._listeners.delete(event);
      }
    }
  }

  // Private helper: remove by entry object reference
  private _removeEntry(event: string, entry: ListenerEntry): void {
    const entries = this._listeners.get(event);
    if (!entries) return;

    const index = entries.indexOf(entry);
    if (index !== -1) {
      entries.splice(index, 1);
      if (entries.length === 0) {
        this._listeners.delete(event);
      }
    }
  }

  // Remove all listeners, optionally scoped to one event
  removeAllListeners(event?: string): void {
    if (event !== undefined) {
      this._listeners.delete(event);
    } else {
      this._listeners.clear();
    }
  }

  // Return number of listeners for an event
  listenerCount(event: string): number {
    return this._listeners.get(event)?.length ?? 0;
  }

  // Return all event names that have at least one listener
  eventNames(): string[] {
    return [...this._listeners.keys()];
  }
}

